mapper.select:
/* BondSaleMapper.getBondSaleObjectLstInfo */
SELECT CONTRACT_NUM , SUB_LINK_NAME , FN_GET_CODENM('BND1000' ,GRNT_INSR_STAT_CHNG_RSN_CD) AS GRNT_INSR_STAT_CHNG_RSN_CD , UNPAID_YN, TTL_INST_AMNT , TTL_INST_MNTH_CNT , MNT_INST_AMT, PAY_AMT, YET_PYMN_AMNT , RMN_INST_CNT , PAY_STRT_DT, PAY_END_DT, GRNT_INSR_MNGM_NO, INST_STRT_DATE, INSR_TRMN_DATE, PYMN_CNT FROM (
SELECT CONTRACT_NUM , SUB_LINK_NAME , GRNT_INSR_STAT_CHNG_RSN_CD , DECODE(UNPAY_ARRS_TMSCNT,0,'N','Y') AS UNPAID_YN, TTL_INST_AMNT , TTL_INST_MNTH_CNT , TRUNC(TTL_INST_AMNT / TTL_INST_MNTH_CNT,-1) AS MNT_INST_AMT, (TTL_INST_AMNT - YET_PYMN_AMNT ) AS PAY_AMT, YET_PYMN_AMNT , RMN_INST_CNT , TO_CHAR(ADD_MONTHS(TO_DATE(INST_STRT_DATE, 'YYYYMMDD'), 1), 'YYYYMM')||'01' AS PAY_STRT_DT, TO_CHAR(LAST_DAY(ADD_MONTHS(TO_DATE(INSR_TRMN_DATE, 'YYYYMMDD'), 1)), 'YYYYMMDD') AS PAY_END_DT, GRNT_INSR_MNGM_NO, INST_STRT_DATE, INSR_TRMN_DATE, MONTHS_BETWEEN(TO_DATE(BILL_YM, 'YYYYMM'), TO_DATE(SUBSTR(GRNT_INSR_MNGM_NO, 0, 6), 'YYYYMM')) - UNPAY_ARRS_TMSCNT AS PYMN_CNT FROM MSP_BOND_ASSET WHERE 1 = 1 AND MST_YN = 'Y' AND CHK_YN = 'N' AND YET_PYMN_AMNT > 0 AND GRNT_INSR_STAT_CHNG_RSN_CD IN ('A1','A3','A6','A9','Y1') AND GRNT_INSR_MNGM_NO NOT IN ( SELECT GRNT_INSR_MNGM_NO FROM MSP_BOND_SALE_DTL A, MSP_BOND_SALE_MST B WHERE A.BOND_SEQ_NO = B.BOND_SEQ_NO AND B.SALE_STAT_CD = 'A' ) ) WHERE 1 = 1
AND INST_STRT_DATE BETWEEN #{trgtStrtDt} AND #{trgtEndDt}
AND YET_PYMN_AMNT >= #{trgtRmnAmt}
AND RMN_INST_CNT >= #{trgtRmnCnt}
AND PYMN_CNT >= #{trgtPymCnt}
AND UNPAID_YN = #{trgtUnpaidYn}
ORDER BY INST_STRT_DATE DESC

/* BondSaleMapper.getBondSaleObjectHap */ SELECT COUNT(GRNT_INSR_MNGM_NO) AS TOTAL_CNT , NVL(SUM(YET_PYMN_AMNT), 0) AS TOTAL_YET_PYMN_AMNT, NVL(CASE WHEN SUM(NVL(BILL_AMNT, 0)) = 0 THEN 0 ELSE ROUND(SUM(PYMN_AMNT)/SUM(BILL_AMNT)*100, 2) END, 0) AS BPYMN_PER, -- 수납율 NVL(CASE WHEN SUM(NVL(PRV_YET_PYMN_AMNT, 0)) = 0 THEN 0 ELSE ROUND(SUM(UNPAY_ARRS_AMNT)/SUM(PRV_YET_PYMN_AMNT)*100, 2) END, 0) AS UNPAY_PER, -- 미납율 NVL(CASE WHEN SUM(NVL(PRV_UNPAY_ARRS_AMNT, 0)) = 0 THEN 0 ELSE ROUND(SUM(UNPAY_AMNT)/SUM(NVL(PRV_UNPAY_ARRS_AMNT, 0))*100, 2) END, 0) AS RTN_PER -- 미납회수율 FROM ( SELECT A.CONTRACT_NUM , A.SUB_LINK_NAME , A.GRNT_INSR_STAT_CHNG_RSN_CD , DECODE(A.UNPAY_ARRS_TMSCNT,0,'N','Y') AS UNPAID_YN, A.TTL_INST_AMNT , A.TTL_INST_MNTH_CNT , (A.TTL_INST_AMNT - A.YET_PYMN_AMNT ) AS PAY_AMT, A.YET_PYMN_AMNT , A.RMN_INST_CNT , TO_CHAR(ADD_MONTHS(TO_DATE(A.INST_STRT_DATE, 'YYYYMMDD'), 1), 'YYYYMM')||'01' AS PAY_STRT_DT, TO_CHAR(LAST_DAY(ADD_MONTHS(TO_DATE(A.INSR_TRMN_DATE, 'YYYYMMDD'), 1)), 'YYYYMMDD') AS PAY_END_DT, A.GRNT_INSR_MNGM_NO, A.INST_STRT_DATE, A.INSR_TRMN_DATE, MONTHS_BETWEEN(TO_DATE(A.BILL_YM, 'YYYYMM'), TO_DATE(SUBSTR(A.GRNT_INSR_MNGM_NO, 0, 6), 'YYYYMM')) - A.UNPAY_ARRS_TMSCNT AS PYMN_CNT, A.UNPAY_ARRS_AMNT, A.BILL_AMNT, A.PYMN_AMNT, A.UNPAY_AMNT, B.UNPAY_ARRS_AMNT AS PRV_UNPAY_ARRS_AMNT, B.YET_PYMN_AMNT AS PRV_YET_PYMN_AMNT FROM MSP_BOND_ASSET A, MSP_BOND_ASSET B WHERE 1 = 1 AND A.GRNT_INSR_MNGM_NO = B.GRNT_INSR_MNGM_NO(+) AND TO_CHAR(ADD_MONTHS(TO_DATE(A.BILL_YM, 'YYYYMM'), -1), 'YYYYMM') = B.BILL_YM(+) AND A.MST_YN = 'Y' AND A.CHK_YN = 'N' AND A.YET_PYMN_AMNT > 0 AND A.GRNT_INSR_STAT_CHNG_RSN_CD IN ('A1','A3','A6','A9','Y1') AND A.GRNT_INSR_MNGM_NO NOT IN ( SELECT GRNT_INSR_MNGM_NO FROM MSP_BOND_SALE_DTL A, MSP_BOND_SALE_MST B WHERE A.BOND_SEQ_NO = B.BOND_SEQ_NO AND B.SALE_STAT_CD = 'A' ) ) WHERE 1 = 1
AND INST_STRT_DATE BETWEEN #{trgtStrtDt} AND #{trgtEndDt}
AND YET_PYMN_AMNT >= #{trgtRmnAmt}
AND RMN_INST_CNT >= #{trgtRmnCnt}
AND PYMN_CNT >= #{trgtPymCnt}
AND UNPAID_YN = #{trgtUnpaidYn}

/* BondSaleMapper.getBondSaleCntrList */ SELECT /*+ FIRST_ROWS */ B.CONTRACT_NUM , B.SUBSCRIBER_NO , B.SUB_LINK_NAME , FN_GET_CODENM('RCP001', B.CUSTOMER_TYPE) AS CUSTOMER_TYPE , DECODE(B.CUSTOMER_TYPE, 'I', SUBSTR(CRYPTO_AES256.DEC_AES(B.USER_SSN),0,6), '') AS USER_SSN , B.TAX_ID , B.SUB_ADR_PRIMARY_LN , C.ORGN_NM AS OPEN_AGNT_CD , B.TTL_INST_AMNT , B.TTL_INST_MNTH_CNT , B.RMN_INST_CNT , TRUNC(B.TTL_INST_AMNT / B.TTL_INST_MNTH_CNT,-1) AS MNT_INST_AMT , TO_CHAR(ADD_MONTHS(TO_DATE(B.INST_STRT_DATE, 'YYYYMMDD'), 1), 'YYYYMM')||'01' AS PAY_STRT_DT , TO_CHAR(LAST_DAY(ADD_MONTHS(TO_DATE(B.INSR_TRMN_DATE, 'YYYYMMDD'), 1)), 'YYYYMMDD') AS PAY_END_DT , B.YET_PYMN_AMNT , A.BOND_SEQ_NO , A.GRNT_INSR_MNGM_NO , DECODE(A.RTN_YM, null, 'N', 'Y') AS RTN_YN , FN_GET_CODENM('BND1000' ,B.GRNT_INSR_STAT_CHNG_RSN_CD) AS GRNT_INSR_STAT_CHNG_RSN_CD FROM MSP_BOND_SALE_DTL A , MSP_BOND_ASSET B , ORG_ORGN_INFO_MST C WHERE 1 = 1 AND A.GRNT_INSR_MNGM_NO = B.GRNT_INSR_MNGM_NO AND A.BOND_SEQ_NO = #{bondSeqNo} AND B.BILL_YM = TO_CHAR(ADD_MONTHS(TO_DATE(A.SALE_YM,'YYYYMM'),-1),'YYYYMM') AND B.OPEN_AGNT_CD = C.ORGN_ID(+)
AND (B.INSR_BILL_AMNT > 0 AND B.UNPAY_AMNT > 0)
AND (B.INSR_BILL_AMNT = 0 OR B.UNPAY_AMNT = 0)
AND B.GRNT_INSR_MNGM_NO = #{pSearchName}
AND B.CONTRACT_NUM = #{pSearchName}
AND B.SUBSCRIBER_NO = #{pSearchName}
AND B.SUB_LINK_NAME = #{pSearchName}
AND DECODE(A.RTN_YM, null, 'N', 'Y') = #{rtnYn}

/* BondSaleMapper.getBondSaleAssetDtlInfo */ SELECT A.GRNT_INSR_MNGM_NO , A.BILL_YM , A.CONTRACT_NUM , A.SUB_LINK_NAME , A.USER_SSN , A.TTL_INST_AMNT , A.TTL_INST_MNTH_CNT , A.TTL_INST_MNTH_AMNT , A.RMN_INST_CNT , A.BPYMN_CNT , A.YET_BILL_AMNT , A.YET_PYMN_AMNT , A.BILL_AMNT , A.PYMN_AMNT , A.UNPAY_AMNT , A.ARRS_FEE_YN , A.ARRS_FEE_AMNT , A.FULL_PRFPAY_YN , A.FULL_PRFPAY_AMNT , A.MID_PRFPAY_YN , A.MID_PRFPAY_AMNT , A.ADJS_YN , A.ADJS_AMNT , A.UNPAY_ARRS_YN , A.UNPAY_ARRS_AMNT , A.UNPAY_ARRS_FEE_AMNT , A.UNPAY_ARRS_TMSCNT , A.UNPAY_YN , A.INSR_BILL_YN , A.INSR_PYMN_YN , A.INSR_BILL_AMNT , A.INSR_PYMN_AMNT , A.MST_YN FROM (SELECT GRNT_INSR_MNGM_NO , BILL_YM , CONTRACT_NUM , SUB_LINK_NAME , USER_SSN , TTL_INST_AMNT , TTL_INST_MNTH_CNT , TRUNC(ROUND(TTL_INST_AMNT/TTL_INST_MNTH_CNT, -1)) AS TTL_INST_MNTH_AMNT , RMN_INST_CNT , CASE WHEN YET_BILL_AMNT = 0 THEN 0 ELSE MONTHS_BETWEEN(TO_DATE(BILL_YM, 'YYYYMM'), TO_DATE(SUBSTR(GRNT_INSR_MNGM_NO, 0, 6), 'YYYYMM')) END AS BPYMN_CNT , YET_BILL_AMNT , YET_PYMN_AMNT , BILL_AMNT , PYMN_AMNT , UNPAY_AMNT , CASE WHEN ARRS_FEE_AMNT > 0 THEN 'Y' ELSE 'N' END AS ARRS_FEE_YN , ARRS_FEE_AMNT , CASE WHEN MID_PRFPAY_AMNT > 0 AND YET_PYMN_AMNT = 0 THEN 'Y' ELSE 'N' END AS FULL_PRFPAY_YN , CASE WHEN MID_PRFPAY_AMNT > 0 AND YET_PYMN_AMNT = 0 THEN MID_PRFPAY_AMNT ELSE 0 END AS FULL_PRFPAY_AMNT , CASE WHEN MID_PRFPAY_AMNT > 0 AND YET_PYMN_AMNT > 0 THEN 'Y' ELSE 'N' END AS MID_PRFPAY_YN , CASE WHEN MID_PRFPAY_AMNT > 0 AND YET_PYMN_AMNT > 0 THEN MID_PRFPAY_AMNT ELSE 0 END AS MID_PRFPAY_AMNT , CASE WHEN ADJS_AMNT > 0 AND GRNT_INSR_STAT_CHNG_RSN_CD NOT IN ('A2', 'A5') THEN 'Y' ELSE 'N' END AS ADJS_YN , ADJS_AMNT , CASE WHEN UNPAY_ARRS_AMNT > 0 THEN 'Y' ELSE 'N' END AS UNPAY_ARRS_YN , UNPAY_ARRS_AMNT , UNPAY_ARRS_FEE_AMNT , UNPAY_ARRS_TMSCNT , DECODE(UNPAY_ARRS_TMSCNT, 0, 'N', 'Y') AS UNPAY_YN , CASE WHEN INSR_BILL_AMNT > 0 AND UNPAY_ARRS_AMNT = 0 THEN 'Y' ELSE 'N' END AS INSR_BILL_YN , CASE WHEN INSR_BILL_AMNT > 0 AND REAL_PYMN_AMNT > 0 AND UNPAY_ARRS_AMNT = 0 THEN 'Y' ELSE 'N' END AS INSR_PYMN_YN , CASE WHEN INSR_BILL_AMNT > 0 AND UNPAY_ARRS_AMNT = 0 THEN INSR_BILL_AMNT ELSE 0 END AS INSR_BILL_AMNT , CASE WHEN INSR_BILL_AMNT > 0 AND REAL_PYMN_AMNT > 0 AND UNPAY_ARRS_AMNT = 0 THEN REAL_PYMN_AMNT ELSE 0 END AS INSR_PYMN_AMNT , MST_YN FROM MSP_BOND_ASSET WHERE 1 = 1 AND GRNT_INSR_MNGM_NO = #{grntInsrMngmNo} ) A , MSP_BOND_SALE_DTL B WHERE 1 = 1 AND A.GRNT_INSR_MNGM_NO = B.GRNT_INSR_MNGM_NO AND B.BOND_SEQ_NO = #{bondSeqNo}
AND A.BILL_YM >= B.SALE_YM
ORDER BY BILL_YM ASC

/* bondSaleMapper.selectSoldAssetList */
SELECT B.CONTRACT_NUM , B.SUB_LINK_NAME , FN_GET_CODENM('RCP001', B.CUSTOMER_TYPE) AS CUSTOMER_TYPE , DECODE(B.CUSTOMER_TYPE, 'I', SUBSTR(CRYPTO_AES256.DEC_AES(B.USER_SSN),0,6), '') AS USER_SSN , B.TAX_ID , B.OPEN_AGNT_CD , C.ORGN_NM , B.SUB_ADR_PRIMARY_LN , B.SUBSCRIBER_NO , TO_CHAR(ADD_MONTHS(TO_DATE(B.INST_STRT_DATE, 'YYYYMMDD'), 1), 'YYYYMM')||'01' AS PAY_STRT_DT , TO_CHAR(LAST_DAY(ADD_MONTHS(TO_DATE(B.INSR_TRMN_DATE, 'YYYYMMDD'), 1)), 'YYYYMMDD') AS PAY_END_DT , '매월말일' AS REDEEM_DT , F_GET_KT_CODE_NM('MSP_JUO_BAN_INFO', 'BL_BILLING_METHOD', B.BL_BILLING_METHOD) AS BL_BILLING_METHOD , B.TTL_INST_AMNT , 0 AS INST_INT_AMT , 0 AS INST_ETC_AMT , B.TTL_INST_AMNT + 0 + 0 AS INST_TOTAL_AMT , (SELECT YET_PYMN_AMNT FROM MSP_BOND_ASSET WHERE GRNT_INSR_MNGM_NO = A.GRNT_INSR_MNGM_NO AND BILL_YM = TO_CHAR(ADD_MONTHS(TO_DATE(A.SALE_YM,'YYYYMM'),-1),'YYYYMM') AND A.RTN_YM IS NULL ) AS BOND_SALE_AMT , 0 AS BOND_SALE_INT_AMT , 0 AS BOND_SALE_ETC_AMT , (SELECT YET_PYMN_AMNT FROM MSP_BOND_ASSET WHERE GRNT_INSR_MNGM_NO = A.GRNT_INSR_MNGM_NO AND BILL_YM = TO_CHAR(ADD_MONTHS(TO_DATE(A.SALE_YM,'YYYYMM'),-1),'YYYYMM') AND A.RTN_YM IS NULL ) + 0 + 0 AS BOND_SALE_TOTAL_AMT , B.YET_PYMN_AMNT , TRUNC(B.TTL_INST_AMNT/B.TTL_INST_MNTH_CNT,-1) AS MON_BILL , B.TTL_INST_MNTH_CNT , B.RMN_INST_CNT , B.GRNT_INSR_MNGM_NO , A.BOND_SEQ_NO FROM MSP_BOND_SALE_DTL A , MSP_BOND_ASSET B , ORG_ORGN_INFO_MST C WHERE 1 = 1 AND A.GRNT_INSR_MNGM_NO = B.GRNT_INSR_MNGM_NO AND B.BILL_YM = #{billYm} AND A.BOND_SEQ_NO = #{bondSeqNo} AND A.RTN_YM IS NULL AND B.OPEN_AGNT_CD = C.ORGN_ID(+)
AND DECODE(B.UNPAY_ARRS_FEE_AMNT,0,'N','Y') = #{billArrAmtYn}
AND DECODE(B.ADJS_AMNT,0,'N','Y') = #{adjsAmtYn}
AND ( B.MID_PRFPAY_AMNT > 0 AND B.YET_PYMN_AMNT = 0 )
AND B.MID_PRFPAY_AMNT = 0
AND ( B.MID_PRFPAY_AMNT > 0 AND B.YET_PYMN_AMNT > 0 )
AND B.MID_PRFPAY_AMNT = 0
AND DECODE(B.INSR_BILL_AMNT,0,'N','Y') = #{insrBillYn}
ORDER BY B.GRNT_INSR_MNGM_NO

/* bondSaleMapper.selectSoldAssetDtlInfo */ SELECT A.GRNT_INSR_MNGM_NO , A.BILL_YM , A.CONTRACT_NUM , A.SUB_LINK_NAME , A.USER_SSN , A.TTL_INST_AMNT , A.TTL_INST_MNTH_CNT , A.TTL_INST_MNTH_AMNT , A.RMN_INST_CNT , A.BPYMN_CNT , A.YET_BILL_AMNT , A.YET_PYMN_AMNT , A.BILL_AMNT , A.PYMN_AMNT , A.UNPAY_AMNT , A.ARRS_FEE_YN , A.ARRS_FEE_AMNT , A.FULL_PRFPAY_YN , A.FULL_PRFPAY_AMNT , A.MID_PRFPAY_YN , A.MID_PRFPAY_AMNT , A.ADJS_YN , A.ADJS_AMNT , A.UNPAY_ARRS_YN , A.UNPAY_ARRS_AMNT , A.UNPAY_ARRS_FEE_AMNT , A.UNPAY_ARRS_TMSCNT , A.UNPAY_YN , A.INSR_BILL_YN , A.INSR_PYMN_YN , A.INSR_BILL_AMNT , A.INSR_PYMN_AMNT FROM (SELECT GRNT_INSR_MNGM_NO , BILL_YM , CONTRACT_NUM , SUB_LINK_NAME , USER_SSN , TTL_INST_AMNT , TTL_INST_MNTH_CNT , TRUNC(ROUND(TTL_INST_AMNT/TTL_INST_MNTH_CNT, -1)) AS TTL_INST_MNTH_AMNT , RMN_INST_CNT , CASE WHEN YET_BILL_AMNT = 0 THEN 0 ELSE MONTHS_BETWEEN(TO_DATE(BILL_YM, 'YYYYMM'), TO_DATE(SUBSTR(GRNT_INSR_MNGM_NO, 0, 6), 'YYYYMM')) END AS BPYMN_CNT , YET_BILL_AMNT , YET_PYMN_AMNT , BILL_AMNT , PYMN_AMNT , UNPAY_AMNT , CASE WHEN ARRS_FEE_AMNT > 0 THEN 'Y' ELSE 'N' END AS ARRS_FEE_YN , ARRS_FEE_AMNT , CASE WHEN MID_PRFPAY_AMNT > 0 AND YET_PYMN_AMNT = 0 THEN 'Y' ELSE 'N' END AS FULL_PRFPAY_YN , CASE WHEN MID_PRFPAY_AMNT > 0 AND YET_PYMN_AMNT = 0 THEN MID_PRFPAY_AMNT ELSE 0 END AS FULL_PRFPAY_AMNT , CASE WHEN MID_PRFPAY_AMNT > 0 AND YET_PYMN_AMNT > 0 THEN 'Y' ELSE 'N' END AS MID_PRFPAY_YN , CASE WHEN MID_PRFPAY_AMNT > 0 AND YET_PYMN_AMNT > 0 THEN MID_PRFPAY_AMNT ELSE 0 END AS MID_PRFPAY_AMNT , CASE WHEN ADJS_AMNT > 0 AND GRNT_INSR_STAT_CHNG_RSN_CD NOT IN ('A2', 'A5') THEN 'Y' ELSE 'N' END AS ADJS_YN , ADJS_AMNT , CASE WHEN UNPAY_ARRS_AMNT > 0 THEN 'Y' ELSE 'N' END AS UNPAY_ARRS_YN , UNPAY_ARRS_AMNT , UNPAY_ARRS_FEE_AMNT , UNPAY_ARRS_TMSCNT , DECODE(UNPAY_ARRS_TMSCNT, 0, 'N', 'Y') AS UNPAY_YN , CASE WHEN INSR_BILL_AMNT > 0 AND UNPAY_ARRS_AMNT = 0 THEN 'Y' ELSE 'N' END AS INSR_BILL_YN , CASE WHEN INSR_BILL_AMNT > 0 AND REAL_PYMN_AMNT > 0 AND UNPAY_ARRS_AMNT = 0 THEN 'Y' ELSE 'N' END AS INSR_PYMN_YN , CASE WHEN INSR_BILL_AMNT > 0 AND UNPAY_ARRS_AMNT = 0 THEN INSR_BILL_AMNT ELSE 0 END AS INSR_BILL_AMNT , CASE WHEN INSR_BILL_AMNT > 0 AND REAL_PYMN_AMNT > 0 AND UNPAY_ARRS_AMNT = 0 THEN REAL_PYMN_AMNT ELSE 0 END AS INSR_PYMN_AMNT FROM MSP_BOND_ASSET WHERE 1 = 1 AND GRNT_INSR_MNGM_NO = #{grntInsrMngmNo} ) A , MSP_BOND_SALE_DTL B WHERE 1 = 1 AND A.GRNT_INSR_MNGM_NO = B.GRNT_INSR_MNGM_NO AND B.BOND_SEQ_NO = #{bondSeqNo}
AND A.BILL_YM >= B.SALE_YM
ORDER BY BILL_YM ASC

/* bondSaleMapper.selectSoldBondStaticInfoList */ SELECT B.SALE_NO , A.BOND_SEQ_NO , A.BILL_YM , A.YET_PYMN_AMNT , A.BILL_AMNT , A.PYMN_AMNT , A.REAL_PYMN_AMNT , A.MID_PRFPAY_AMNT , A.UNPAY_AMNT , A.ARRS_FEE_AMNT , A.UNPAY_ARRS_AMNT , A.UNPAY_ARRS_FEE_AMNT , A.ADJS_AMNT , A.NR_FULL_PRFPAY_AMNT , A.NR_MID_PRFPAY_AMNT , A.NR_PYMN_AMNT , A.NR_CANC_AMNT , A.NR_RTN_AMNT , A.INSR_BILL_AMNT , A.INSR_PYMN_AMNT , A.RUN_AMNT , A.RUN_USR_ID , A.RUN_DT , A.BOND_CNT , A.NR_FULL_PRFPAY_CNT , A.NR_MID_PRFPAY_CNT , A.NR_PYMN_CNT , A.NR_CANC_CNT , A.ADJ_CNT , A.INSR_BILL_CNT , A.INSR_PYMN_CNT , A.NR_RTN_CNT , A.YET_PYMN_AMNT_00 , A.YET_PYMN_AMNT_01 , A.YET_PYMN_AMNT_02 , A.YET_PYMN_AMNT_03 , A.YET_PYMN_AMNT_04 , A.YET_PYMN_AMNT_05 , A.YET_PYMN_AMNT_06 , A.YET_PYMN_AMNT_07 , A.YET_PYMN_AMNT_08 , A.YET_PYMN_AMNT_09 , A.YET_PYMN_AMNT_10 , A.YET_PYMN_AMNT_11 , A.YET_PYMN_AMNT_12 , A.REG_ID , A.REG_DTTM , A.CHNG_ID , A.CHNG_DTTM , YET_PYMN_AMNT + REAL_PYMN_AMNT + MID_PRFPAY_AMNT + ADJS_AMNT + NR_CANC_AMNT AS MNTH_FST_AMT , (INSR_BILL_AMNT - INSR_PYMN_AMNT) AS INSR_MTG_AMT , 0 AS INSR_BCK_INT_AMT , BOND_CNT - NR_FULL_PRFPAY_CNT - NR_PYMN_CNT - INSR_PYMN_CNT - NR_RTN_CNT AS MNTH_LST_CNT , NVL((SELECT UNPAY_ARRS_AMNT FROM MSP_BOND_SALE_STTC WHERE BILL_YM = TO_CHAR(ADD_MONTHS(TO_DATE(A.BILL_YM, 'YYYYMM'), -1), 'YYYYMM') and BOND_SEQ_NO = A.BOND_SEQ_NO ),0) AS DLY_BILL_AMT FROM MSP_BOND_SALE_STTC A , MSP_BOND_SALE_MST B WHERE 1 = 1 AND A.BOND_SEQ_NO = B.BOND_SEQ_NO
AND A.BOND_SEQ_NO = #{bondSeqNo}
ORDER BY A.BOND_SEQ_NO, A.BILL_YM ASC

mapper.update:
/** BondSaleMapper.confirmReceipt */
UPDATE 
      MSP_BOND_SALE_STTC
SET
      RUN_AMNT = #{mtgPayAmt}
      , RUN_USR_ID = #{sessionUserId}
      , RUN_DT = #{runDt}
WHERE 1=1
      AND BILL_YM = #{billYm}
      AND BOND_SEQ_NO = #{bondSeqNo}

mapper.select:
/* BondSaleMapper.selectSaleBckInfoList */ SELECT
A.RTN_RSN , B.YET_PYMN_AMNT AS RTN_AMT , A.RTN_YM , FN_GET_USRNM(A.RTN_ID) AS RTN_ID , A.BOND_SEQ_NO , B.CONTRACT_NUM , A.GRNT_INSR_MNGM_NO , B.SUBSCRIBER_NO , C.SALE_NO FROM MSP_BOND_SALE_DTL A , MSP_BOND_ASSET B , MSP_BOND_SALE_MST C WHERE 1=1 AND A.GRNT_INSR_MNGM_NO = B.GRNT_INSR_MNGM_NO AND A.RTN_YM = B.BILL_YM AND A.RTN_YM IS NOT NULL AND A.BOND_SEQ_NO = C.BOND_SEQ_NO
AND A.BOND_SEQ_NO = #{bondSeqNo}
ORDER BY A.RTN_YM DESC
